SELECT data_id, COUNT(version_id) AS version_count
FROM data_versions
GROUP BY data_id;

SELECT year, real_gdi
FROM economic_data
ORDER BY year DESC;

SELECT quarter, AVG(real_gdi) AS Average_Real_GDI
FROM economic_data
GROUP BY quarter;

SELECT source_name, website
FROM data_sources
WHERE data_frequency IN ('annually', 'monthly');

SELECT data_id, year, quarter, real_gdi, real_gdp, nominal_gdp, source_id, currency_unit, seasonally_adjusted, notes, created_at, updated_at
FROM economic_data
WHERE real_gdi > (SELECT AVG(real_gdi) FROM economic_data);

SELECT * 
FROM economic_data
ORDER BY year;

SELECT ed.data_id, ed.year, ed.real_gdp
FROM economic_data ed
WHERE ed.year != 2020 AND ed.real_gdp > (SELECT AVG(real_gdp) FROM economic_data);

SELECT DISTINCT user_name, email
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM reports
) AND user_id IN (
  SELECT user_id
  FROM access_logs
);
